INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('col_negotiation_01', 'reach', 'an agreement', 'reach an agreement', '합의에 도달하다', 'make', '"make an agreement"도 쓰이지만 reach는 양측이 노력 끝에 도달하는 뉘앙스예요.', 'After long negotiations, both sides reached an agreement.', '오랜 협상 끝에 양측은 합의에 도달했어요.', 'We hope to reach an agreement before the end of the month.', '이달 말 전에 합의에 도달하기를 바라요.', 'B1', 'negotiation', 1, 'agreement handshake deal business negotiation', 1),
('col_negotiation_02', 'make', 'a concession', 'make a concession', '양보하다', 'do', '"do a concession"은 틀린 표현이에요. 양보할 때는 make a concession을 써요.', 'Both sides had to make concessions to reach the final deal.', '양측은 최종 합의에 이르기 위해 양보해야 했어요.', 'She made a small concession on the price to close the deal quickly.', '그녀는 거래를 빨리 성사시키기 위해 가격에 대해 약간 양보했어요.', 'B2', 'negotiation', 2, 'concession deal negotiation business compromise', 2),
('col_negotiation_03', 'strike', 'a deal', 'strike a deal', '거래를 성사시키다', 'make', '"make a deal"도 맞지만 strike a deal은 더 극적이고 결정적인 순간을 강조해요.', 'The two companies struck a deal worth 50 million dollars.', '두 회사는 5000만 달러 규모의 거래를 성사시켰어요.', 'He struck a deal with the supplier after weeks of back-and-forth.', '그는 수 주간의 협상 끝에 공급업체와 거래를 성사시켰어요.', 'B2', 'negotiation', 2, 'deal business agreement contract strike', 3),
('col_negotiation_04', 'walk away', 'from the table', 'walk away from the table', '협상 테이블을 떠나다', 'leave', '"leave the table"도 맞지만 walk away from the table은 협상 결렬을 더 강하게 표현해요.', 'If the offer isn''t improved, we will walk away from the table.', '제안이 개선되지 않으면 우리는 협상 테이블을 떠날 거예요.', 'She walked away from the table when they refused her key demand.', '그들이 핵심 요구를 거부하자 그녀는 협상 테이블을 떠났어요.', 'B2', 'negotiation', 2, 'walk away negotiation deal table', 4),
('col_negotiation_05', 'drive', 'a hard bargain', 'drive a hard bargain', '강하게 협상하다', 'make', '"make a hard bargain"은 어색해요. 강경하게 협상할 때는 drive a hard bargain을 써요.', 'He''s known for driving a hard bargain in contract negotiations.', '그는 계약 협상에서 강하게 협상하는 것으로 알려져 있어요.', 'She drives a hard bargain but always keeps her word.', '그녀는 강하게 협상하지만 항상 약속을 지켜요.', 'C1', 'negotiation', 3, 'bargain negotiation strong deal hard', 5),
('col_negotiation_06', 'come to', 'the table', 'come to the table', '협상 테이블에 나서다', 'join', '"join the negotiation"도 맞지만 come to the table은 협상 참여 의사를 나타내는 표현이에요.', 'Both parties need to come to the table with an open mind.', '양측은 열린 마음으로 협상 테이블에 나서야 해요.', 'The union agreed to come to the table after the management made new offers.', '경영진이 새로운 제안을 내놓자 노조는 협상 테이블에 나서기로 합의했어요.', 'C1', 'negotiation', 3, 'table negotiation meeting deal', 6),
('col_negotiation_07', 'set', 'terms', 'set terms', '조건을 정하다', 'make', '"make terms"는 어색해요. 협상 조건을 정할 때는 set terms를 써요.', 'Before signing, you should clearly set the terms of the agreement.', '서명하기 전에 합의 조건을 명확하게 정해야 해요.', 'The landlord set strict terms for the lease renewal.', '집주인은 임대 갱신에 대한 엄격한 조건을 정했어요.', 'B2', 'negotiation', 2, 'terms conditions agreement contract legal', 7),
('col_negotiation_08', 'bridge', 'a gap', 'bridge a gap', '격차를 좁히다', 'close', '"close a gap"도 맞지만 bridge a gap은 양측의 차이를 잇는 뉘앙스예요.', 'The mediator helped bridge the gap between the two sides.', '중재자는 양측의 격차를 좁히는 데 도움을 줬어요.', 'We need to bridge the gap in salary expectations before we proceed.', '진행하기 전에 급여 기대치의 격차를 좁혀야 해요.', 'C1', 'negotiation', 3, 'gap bridge difference negotiation compromise', 8),
('col_negotiation_09', 'put', 'on the table', 'put something on the table', '제안을 내놓다', 'say', '"say an offer"는 어색해요. 제안을 공식적으로 내놓을 때는 put on the table을 써요.', 'What can you put on the table to make this deal work?', '이 거래를 성사시키기 위해 어떤 제안을 내놓을 수 있어요?', 'They put a generous severance package on the table to end the dispute.', '그들은 분쟁을 종식시키기 위해 넉넉한 퇴직금 패키지를 제안으로 내놓았어요.', 'B2', 'negotiation', 2, 'offer proposal table negotiation deal', 9),
('col_negotiation_10', 'hold', 'firm', 'hold firm', '입장을 굳건히 유지하다', 'stay', '"stay firm"도 맞지만 hold firm은 압박에도 흔들리지 않는다는 뉘앙스예요.', 'Despite the pressure, she held firm on her original offer.', '압박에도 불구하고 그녀는 원래 제안에 입장을 굳건히 유지했어요.', 'The union held firm on its demand for a 10% pay rise.', '노조는 10% 임금 인상 요구에 대해 입장을 굳건히 유지했어요.', 'B2', 'negotiation', 2, 'firm hold position negotiation pressure', 10),
('col_negotiation_11', 'draw up', 'a contract', 'draw up a contract', '계약서를 작성하다', 'make', '"make a contract"도 쓰이지만 draw up은 공식 문서를 법적으로 작성하는 뉘앙스예요.', 'The lawyer drew up a contract for both parties to sign.', '변호사는 양측이 서명할 계약서를 작성했어요.', 'We''ll draw up a contract once we''ve agreed on all the terms.', '모든 조건에 합의하면 계약서를 작성할게요.', 'B2', 'negotiation', 2, 'contract legal document business agreement', 11),
('col_negotiation_12', 'meet', 'in the middle', 'meet in the middle', '절충점을 찾다', 'compromise', '"compromise"도 맞지만 meet in the middle은 양측이 동등하게 양보하는 뉘앙스예요.', 'They met in the middle on price, and the deal was closed.', '그들은 가격에서 절충점을 찾았고 거래가 성사됐어요.', 'If you can meet in the middle, we can move forward today.', '절충점을 찾을 수 있다면 오늘 바로 진행할 수 있어요.', 'B1', 'negotiation', 1, 'compromise middle meet deal negotiation', 12),
('col_negotiation_13', 'reject', 'an offer', 'reject an offer', '제안을 거절하다', 'refuse', '"refuse an offer"도 맞지만 reject는 더 공식적인 거절을 강조해요.', 'She rejected the first offer and proposed a counter-offer.', '그녀는 첫 번째 제안을 거절하고 반대 제안을 했어요.', 'The board rejected the offer due to concerns about long-term viability.', '이사회는 장기적인 실행 가능성에 대한 우려로 제안을 거절했어요.', 'B1', 'negotiation', 1, 'rejection offer deal negotiation refuse', 13),
('col_negotiation_14', 'push', 'for better terms', 'push for better terms', '더 나은 조건을 요구하다', 'ask', '"ask for better terms"도 맞지만 push는 더 강하게 요구한다는 뉘앙스예요.', 'The employee pushed for better terms before agreeing to the contract.', '직원은 계약에 동의하기 전에 더 나은 조건을 강하게 요구했어요.', 'You have more leverage than you think — push for better terms.', '생각보다 협상력이 있어요. 더 나은 조건을 요구해 보세요.', 'C1', 'negotiation', 3, 'terms negotiation push demand better', 14),
('col_negotiation_15', 'sign', 'a contract', 'sign a contract', '계약서에 서명하다', 'write', '"write a contract"는 작성하는 것이고 sign은 서명하는 것이에요. 혼동하지 마세요.', 'Both parties signed the contract and shook hands.', '양측은 계약서에 서명하고 악수를 나눴어요.', 'She refused to sign the contract until all the changes were made.', '그녀는 모든 변경 사항이 이루어질 때까지 계약서에 서명하기를 거부했어요.', 'B1', 'negotiation', 1, 'contract sign agreement legal business', 15),
('col_negotiation_16', 'negotiate', 'a price', 'negotiate a price', '가격을 협상하다', 'discuss', '"discuss a price"도 맞지만 negotiate는 서로 다른 입장에서 조율하는 뉘앙스예요.', 'In many countries, it''s normal to negotiate the price at a market.', '많은 나라에서 시장에서 가격을 협상하는 것이 일반적이에요.', 'She was able to negotiate a lower price for the property.', '그녀는 부동산의 더 낮은 가격을 협상할 수 있었어요.', 'B1', 'negotiation', 1, 'price negotiation deal business market', 16),
('col_negotiation_17', 'break down', 'negotiations', 'break down in negotiations', '협상이 결렬되다', 'fail', '"fail in negotiations"도 맞지만 break down은 협상이 갑자기 결렬되는 뉘앙스예요.', 'Negotiations broke down after a key disagreement on delivery terms.', '납기 조건에 대한 핵심적인 이견 이후 협상이 결렬됐어요.', 'If talks break down, we will need to find another solution.', '협상이 결렬되면 다른 해결책을 찾아야 해요.', 'B2', 'negotiation', 2, 'breakdown negotiation failure deal talks', 17),
('col_negotiation_18', 'table', 'a proposal', 'table a proposal', '제안을 제출하다', 'bring', '"bring a proposal"도 맞지만 table a proposal은 공식적인 안건 제출을 강조해요.', 'The union tabled a proposal for a four-day work week.', '노조는 주 4일 근무제에 대한 제안을 제출했어요.', 'We''d like to table a proposal before the meeting ends.', '회의가 끝나기 전에 제안을 제출하고 싶어요.', 'C1', 'negotiation', 3, 'proposal table submission meeting official', 18),
('col_negotiation_19', 'finalize', 'an agreement', 'finalize an agreement', '합의를 최종 확정하다', 'finish', '"finish an agreement"는 어색해요. 합의를 최종 확정할 때는 finalize를 써요.', 'Both teams worked late to finalize the agreement before the deadline.', '양 팀은 마감 기한 전에 합의를 최종 확정하기 위해 늦게까지 일했어요.', 'We expect to finalize the agreement by the end of the week.', '이번 주말까지 합의를 최종 확정할 것으로 기대해요.', 'B2', 'negotiation', 2, 'agreement finalize deal close contract', 19),
('col_negotiation_20', 'leverage', 'a position', 'leverage a position', '유리한 위치를 활용하다', 'use', '"use a position"도 맞지만 leverage는 전략적으로 강점을 활용하는 뉘앙스예요.', 'They leveraged their market position to negotiate better prices.', '그들은 더 나은 가격을 협상하기 위해 시장 지위를 활용했어요.', 'She leveraged her expertise to secure a favorable contract.', '그녀는 유리한 계약을 따내기 위해 전문성을 활용했어요.', 'C1', 'negotiation', 3, 'leverage position strength negotiation strategy', 20);
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('col_humanities_01', 'draw', 'a conclusion', 'draw a conclusion', '결론을 도출하다', 'make', '"make a conclusion"은 어색해요. 논리적 추론으로 결론을 낼 때는 draw를 써요.', 'From the evidence, we can draw a conclusion about the author''s intent.', '증거로부터 작가의 의도에 대한 결론을 도출할 수 있어요.', 'Historians draw conclusions by carefully examining primary sources.', '역사가들은 1차 자료를 주의 깊게 검토하여 결론을 도출해요.', 'B2', 'humanities', 2, 'conclusion research analysis study humanities', 1),
('col_humanities_02', 'trace', 'the origins', 'trace the origins', '기원을 추적하다', 'find', '"find the origins"도 맞지만 trace는 역사적 경로를 따라가는 뉘앙스예요.', 'Scholars have traced the origins of the English language to Anglo-Saxon.', '학자들은 영어의 기원을 앵글로색슨어까지 추적해 왔어요.', 'It''s fascinating to trace the origins of common words and phrases.', '일반적인 단어와 구절의 기원을 추적하는 것은 흥미로워요.', 'B2', 'humanities', 2, 'origins history trace etymology culture', 2),
('col_humanities_03', 'conduct', 'research', 'conduct research', '연구를 수행하다', 'do', '"do research"도 맞지만 conduct research는 더 격식 있고 체계적인 연구를 강조해요.', 'She conducted extensive research into medieval literature.', '그녀는 중세 문학에 대해 광범위한 연구를 수행했어요.', 'The university is conducting research on the effects of social media on language.', '대학은 소셜 미디어가 언어에 미치는 영향에 대한 연구를 수행하고 있어요.', 'B2', 'humanities', 2, 'research academic university library study', 3),
('col_humanities_04', 'interpret', 'a text', 'interpret a text', '텍스트를 해석하다', 'read', '"read a text"는 단순히 읽는 것이고 interpret는 의미를 분석하고 해석하는 것이에요.', 'Students are asked to interpret the text from a feminist perspective.', '학생들은 페미니스트 관점에서 텍스트를 해석하도록 요청받아요.', 'How you interpret a text depends heavily on your cultural background.', '텍스트를 어떻게 해석하는지는 문화적 배경에 크게 좌우돼요.', 'B2', 'humanities', 2, 'text interpretation literature analysis reading', 4),
('col_humanities_05', 'challenge', 'a theory', 'challenge a theory', '이론에 의문을 제기하다', 'question', '"question a theory"도 맞지만 challenge는 더 적극적인 반박을 강조해요.', 'New archaeological findings challenge the established theory about ancient migration.', '새로운 고고학적 발견은 고대 이주에 대한 기존 이론에 의문을 제기해요.', 'The essay challenges the theory that art reflects society passively.', '그 에세이는 예술이 사회를 수동적으로 반영한다는 이론에 의문을 제기해요.', 'C1', 'humanities', 3, 'theory challenge critique academic debate', 5),
('col_humanities_06', 'shed light on', 'history', 'shed light on history', '역사에 빛을 비추다, 역사를 밝히다', 'explain', '"explain history"도 맞지만 shed light on은 새로운 이해나 통찰을 제공하는 뉘앙스예요.', 'New documents shed light on a period of history that was previously misunderstood.', '새로운 문서들이 이전에 잘못 이해됐던 역사적 시기를 밝혀줬어요.', 'The research sheds light on how ancient societies dealt with climate change.', '그 연구는 고대 사회가 기후 변화에 어떻게 대처했는지를 밝혀줘요.', 'C1', 'humanities', 3, 'history revelation research light understanding', 6),
('col_humanities_07', 'analyse', 'a text', 'analyse a text', '텍스트를 분석하다', 'study', '"study a text"도 맞지만 analyse는 더 비판적이고 체계적인 분석을 강조해요.', 'The class was asked to analyse the text using literary theory.', '수업에서 문학 이론을 사용하여 텍스트를 분석하도록 요청받았어요.', 'She analysed the text to identify recurring themes and motifs.', '그녀는 반복되는 주제와 모티프를 찾아내기 위해 텍스트를 분석했어요.', 'B2', 'humanities', 2, 'analysis text literary critical study', 7),
('col_humanities_08', 'preserve', 'a manuscript', 'preserve a manuscript', '원고를 보존하다', 'keep', '"keep a manuscript"는 어색해요. 원고와 같은 문화유산을 보존할 때는 preserve를 써요.', 'The library works to preserve ancient manuscripts from deterioration.', '도서관은 고대 원고가 손상되지 않도록 보존하기 위해 노력해요.', 'Digitizing books is a modern way to preserve important manuscripts.', '책을 디지털화하는 것은 중요한 원고를 보존하는 현대적인 방법이에요.', 'B1', 'humanities', 1, 'manuscript library archive preservation history', 8),
('col_humanities_09', 'cite', 'a source', 'cite a source', '출처를 인용하다', 'use', '"use a source"도 맞지만 cite는 공식적으로 출처를 명시하는 것을 강조해요.', 'Always cite your sources when writing an academic essay.', '학술 에세이를 작성할 때는 항상 출처를 인용하세요.', 'She cited three primary sources to support her argument.', '그녀는 자신의 주장을 뒷받침하기 위해 세 가지 1차 출처를 인용했어요.', 'B1', 'humanities', 1, 'citation source reference academic essay', 9),
('col_humanities_10', 'examine', 'evidence', 'examine evidence', '증거를 검토하다', 'look at', '"look at evidence"도 쓰이지만 examine은 더 꼼꼼하고 체계적인 검토를 강조해요.', 'The historian examined the evidence before writing her conclusions.', '역사가는 결론을 쓰기 전에 증거를 검토했어요.', 'We need to examine all available evidence before making a judgment.', '판단을 내리기 전에 모든 가용 증거를 검토해야 해요.', 'B2', 'humanities', 2, 'evidence research examine analyze study', 10),
('col_humanities_11', 'explore', 'a theme', 'explore a theme', '주제를 탐구하다', 'find', '"find a theme"도 맞지만 explore는 주제를 깊이 탐구하는 뉘앙스예요.', 'The novel explores the theme of identity in modern society.', '그 소설은 현대 사회에서의 정체성이라는 주제를 탐구해요.', 'The lecture explored the theme of power in Shakespeare''s plays.', '강의는 셰익스피어 희곡에서 권력이라는 주제를 탐구했어요.', 'B2', 'humanities', 2, 'theme exploration literature analysis subject', 11),
('col_humanities_12', 'question', 'assumptions', 'question assumptions', '가정에 의문을 품다', 'doubt', '"doubt assumptions"도 맞지만 question은 건설적인 비판적 사고를 강조해요.', 'Great philosophers question the assumptions of their time.', '위대한 철학자들은 자신의 시대의 가정에 의문을 품어요.', 'The course encourages students to question their own cultural assumptions.', '그 과목은 학생들이 자신의 문화적 가정에 의문을 품도록 독려해요.', 'C1', 'humanities', 3, 'question assumption philosophy critical culture', 12),
('col_humanities_13', 'convey', 'meaning', 'convey meaning', '의미를 전달하다', 'show', '"show meaning"도 맞지만 convey는 의도적으로 의미를 전달하는 뉘앙스예요.', 'The painting conveys a deep sense of loss through its dark colour palette.', '그 그림은 어두운 색채 팔레트를 통해 깊은 상실감을 전달해요.', 'Language can convey subtle meanings that body language cannot.', '언어는 몸짓 언어가 전달하지 못하는 미묘한 의미를 전달할 수 있어요.', 'B2', 'humanities', 2, 'meaning convey communication language expression', 13),
('col_humanities_14', 'draw on', 'sources', 'draw on sources', '자료를 활용하다', 'use', '"use sources"도 맞지만 draw on은 다양한 출처에서 선택적으로 활용하는 뉘앙스예요.', 'The author drew on a wide range of historical sources to write the novel.', '저자는 소설을 쓰기 위해 다양한 역사적 자료를 활용했어요.', 'Good academic writing draws on both primary and secondary sources.', '좋은 학술 글쓰기는 1차 및 2차 자료를 모두 활용해요.', 'C1', 'humanities', 3, 'sources research draw academic reference', 14),
('col_humanities_15', 'make', 'an argument', 'make an argument', '주장을 펼치다', 'say', '"say an argument"는 어색해요. 논거를 제시하며 주장할 때는 make an argument를 써요.', 'The essay makes a compelling argument for the preservation of indigenous languages.', '그 에세이는 토착 언어 보존을 위한 설득력 있는 주장을 펼쳐요.', 'She made a strong argument during the seminar discussion.', '그녀는 세미나 토론에서 강력한 주장을 펼쳤어요.', 'B2', 'humanities', 2, 'argument essay academic debate humanities', 15),
('col_humanities_16', 'reflect on', 'the past', 'reflect on the past', '과거를 성찰하다', 'think about', '"think about the past"도 맞지만 reflect on은 더 깊은 사고와 통찰을 강조해요.', 'Historians reflect on the past to understand patterns in human behavior.', '역사가들은 인간 행동의 패턴을 이해하기 위해 과거를 성찰해요.', 'The memoir encourages readers to reflect on their own past experiences.', '그 회고록은 독자들이 자신의 과거 경험을 성찰하도록 이끌어요.', 'B2', 'humanities', 2, 'reflection past history memory thinking', 16),
('col_humanities_17', 'engage with', 'literature', 'engage with literature', '문학과 상호작용하다', 'read', '"read literature"도 맞지만 engage with는 단순히 읽는 것을 넘어 적극적으로 상호작용하는 것이에요.', 'Students are encouraged to actively engage with the literature, not just read it.', '학생들은 문학을 단순히 읽는 것을 넘어 적극적으로 상호작용하도록 독려받아요.', 'She engages with literature by asking questions and forming her own opinions.', '그녀는 질문하고 자신의 의견을 형성함으로써 문학과 상호작용해요.', 'C1', 'humanities', 3, 'literature engage reading critical thinking', 17),
('col_humanities_18', 'reshape', 'history', 'reshape history', '역사를 새롭게 쓰다', 'change', '"change history"도 맞지만 reshape는 역사의 이해나 방향을 바꾸는 뉘앙스예요.', 'New discoveries can reshape our understanding of ancient history.', '새로운 발견은 고대 역사에 대한 우리의 이해를 새롭게 쓸 수 있어요.', 'Social movements have the power to reshape history.', '사회 운동은 역사를 새롭게 쓸 힘을 가지고 있어요.', 'C1', 'humanities', 3, 'history reshape change society impact', 18),
('col_humanities_19', 'place', 'in context', 'place in context', '맥락 속에 위치시키다', 'explain', '"explain"도 맞지만 place in context는 더 넓은 배경 속에서 이해하는 뉘앙스예요.', 'To understand the poem, you need to place it in its historical context.', '시를 이해하려면 역사적 맥락 속에 위치시켜야 해요.', 'She placed the painting in the context of the Renaissance movement.', '그녀는 그 그림을 르네상스 운동의 맥락 속에 위치시켰어요.', 'B2', 'humanities', 2, 'context history culture setting interpretation', 19),
('col_humanities_20', 'raise', 'awareness', 'raise awareness', '인식을 높이다', 'increase', '"increase awareness"도 맞지만 raise awareness는 사람들의 주의를 끄는 더 자연스러운 표현이에요.', 'The humanities help raise awareness of diverse cultural perspectives.', '인문학은 다양한 문화적 관점에 대한 인식을 높이는 데 도움이 돼요.', 'The documentary raised awareness about the loss of endangered languages.', '그 다큐멘터리는 멸종 위기 언어의 소실에 대한 인식을 높였어요.', 'B1', 'humanities', 1, 'awareness culture education raise society', 20);
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('col_technology_01', 'develop', 'software', 'develop software', '소프트웨어를 개발하다', 'make', '"make software"도 쓰이지만 develop은 전문적인 개발 과정을 강조해요.', 'The team spent six months developing the new software platform.', '팀은 새로운 소프트웨어 플랫폼을 개발하는 데 6개월을 보냈어요.', 'She develops software for financial institutions around the world.', '그녀는 전 세계 금융 기관을 위한 소프트웨어를 개발해요.', 'B1', 'technology', 1, 'software development coding tech laptop', 1),
('col_technology_02', 'run', 'a program', 'run a program', '프로그램을 실행하다', 'open', '"open a program"도 맞지만 run은 프로그램이 실행되는 것을 강조해요.', 'You can run the program by double-clicking the icon.', '아이콘을 더블 클릭하면 프로그램을 실행할 수 있어요.', 'The server runs the program automatically every night at midnight.', '서버는 매일 밤 자정에 자동으로 프로그램을 실행해요.', 'B1', 'technology', 1, 'program computer run software execute', 2),
('col_technology_03', 'launch', 'an app', 'launch an app', '앱을 출시하다', 'make', '"make an app"은 앱을 만드는 것이에요. 공식적으로 출시할 때는 launch를 써요.', 'The startup launched its new app to great critical acclaim.', '그 스타트업은 큰 호평을 받으며 새 앱을 출시했어요.', 'They plan to launch the app in three new markets next year.', '그들은 내년에 세 개의 새 시장에서 앱을 출시할 계획이에요.', 'B1', 'technology', 1, 'app launch startup mobile release', 3),
('col_technology_04', 'store', 'data', 'store data', '데이터를 저장하다', 'save', '"save data"도 맞지만 store는 시스템이나 클라우드에 저장하는 더 기술적인 표현이에요.', 'The system stores all user data on secure cloud servers.', '시스템은 모든 사용자 데이터를 안전한 클라우드 서버에 저장해요.', 'Companies must be transparent about how they store personal data.', '기업은 개인 데이터를 어떻게 저장하는지 투명하게 공개해야 해요.', 'B1', 'technology', 1, 'data storage cloud server digital', 4),
('col_technology_05', 'process', 'data', 'process data', '데이터를 처리하다', 'analyse', '"analyse data"도 맞지만 process는 데이터를 변환하거나 처리하는 기계적 단계를 강조해요.', 'The algorithm can process millions of data points per second.', '알고리즘은 초당 수백만 개의 데이터 포인트를 처리할 수 있어요.', 'Modern computers process data far faster than those of twenty years ago.', '현대 컴퓨터는 20년 전보다 훨씬 빠르게 데이터를 처리해요.', 'B2', 'technology', 2, 'data process computing AI speed', 5),
('col_technology_06', 'update', 'software', 'update software', '소프트웨어를 업데이트하다', 'change', '"change software"는 다른 의미예요. 버전을 최신화할 때는 update를 써요.', 'Remember to update your software regularly to stay protected from threats.', '위협으로부터 보호받기 위해 소프트웨어를 정기적으로 업데이트하세요.', 'The company updated its software to fix a critical security vulnerability.', '회사는 심각한 보안 취약점을 수정하기 위해 소프트웨어를 업데이트했어요.', 'B1', 'technology', 1, 'software update security patch digital', 6),
('col_technology_07', 'breach', 'security', 'breach security', '보안을 침해하다', 'break', '"break security"도 쓰이지만 breach는 보안 맥락에서 더 전문적인 표현이에요.', 'Hackers breached the company''s security and stole customer data.', '해커들이 회사의 보안을 침해하고 고객 데이터를 훔쳤어요.', 'The system was designed to prevent anyone from breaching its security.', '그 시스템은 누구도 보안을 침해할 수 없도록 설계됐어요.', 'B2', 'technology', 2, 'security breach hacker cyber privacy', 7),
('col_technology_08', 'integrate', 'systems', 'integrate systems', '시스템을 통합하다', 'connect', '"connect systems"도 맞지만 integrate는 여러 시스템을 하나로 합치는 뉘앙스예요.', 'The project aims to integrate the company''s existing systems into one platform.', '그 프로젝트는 회사의 기존 시스템을 하나의 플랫폼으로 통합하는 것을 목표로 해요.', 'Integrating new software with legacy systems can be challenging.', '새 소프트웨어를 기존 시스템과 통합하는 것은 어려울 수 있어요.', 'B2', 'technology', 2, 'integration system platform technology connect', 8),
('col_technology_09', 'automate', 'a process', 'automate a process', '프로세스를 자동화하다', 'do automatically', '"do automatically"는 어색해요. 업무나 프로세스를 자동화할 때는 automate를 써요.', 'The company has automated its invoicing process to save time.', '회사는 시간을 절약하기 위해 청구서 발행 프로세스를 자동화했어요.', 'AI is increasingly used to automate repetitive tasks in the workplace.', '직장에서 반복적인 업무를 자동화하기 위해 AI가 점점 더 많이 사용되고 있어요.', 'B2', 'technology', 2, 'automation AI process technology efficiency', 9),
('col_technology_10', 'deploy', 'a solution', 'deploy a solution', '솔루션을 배포하다', 'use', '"use a solution"도 맞지만 deploy는 기술적 맥락에서 시스템을 가동하는 전문 표현이에요.', 'The IT team deployed the new solution across all departments.', 'IT 팀은 모든 부서에 새 솔루션을 배포했어요.', 'They plan to deploy the software update in three phases.', '그들은 3단계로 소프트웨어 업데이트를 배포할 계획이에요.', 'C1', 'technology', 3, 'deploy solution IT system rollout', 10),
('col_technology_11', 'troubleshoot', 'an issue', 'troubleshoot an issue', '문제를 해결하다', 'fix', '"fix an issue"도 맞지만 troubleshoot은 원인을 찾아 해결하는 과정을 강조해요.', 'The engineer spent three hours troubleshooting the network issue.', '엔지니어는 3시간 동안 네트워크 문제를 해결하는 데 시간을 보냈어요.', 'If you troubleshoot the issue before calling support, it often saves time.', '지원팀에 연락하기 전에 문제를 해결하려고 시도하면 시간을 절약할 수 있어요.', 'B2', 'technology', 2, 'troubleshoot issue fix error tech support', 11),
('col_technology_12', 'back up', 'data', 'back up data', '데이터를 백업하다', 'save', '"save data"도 맞지만 back up은 복사본을 만들어 보호하는 뉘앙스예요.', 'You should back up your data regularly in case of system failure.', '시스템 장애에 대비해 데이터를 정기적으로 백업해야 해요.', 'The IT department backs up all company data every 24 hours.', 'IT 부서는 24시간마다 모든 회사 데이터를 백업해요.', 'B1', 'technology', 1, 'backup data storage cloud recovery', 12),
('col_technology_13', 'encrypt', 'data', 'encrypt data', '데이터를 암호화하다', 'protect', '"protect data"도 맞지만 encrypt는 데이터를 암호화하는 특정 기술 방법을 강조해요.', 'All sensitive data is encrypted before being transmitted.', '모든 민감한 데이터는 전송 전에 암호화돼요.', 'You should encrypt your data to prevent unauthorized access.', '무단 접근을 방지하기 위해 데이터를 암호화해야 해요.', 'B2', 'technology', 2, 'encryption data security privacy digital', 13),
('col_technology_14', 'scale up', 'operations', 'scale up operations', '운영 규모를 확대하다', 'grow', '"grow operations"도 맞지만 scale up은 기술 스타트업 맥락에서 더 자연스러운 표현이에요.', 'The startup scaled up operations after securing Series B funding.', '그 스타트업은 시리즈 B 투자를 받은 후 운영 규모를 확대했어요.', 'Cloud infrastructure makes it easy to scale up operations quickly.', '클라우드 인프라는 빠르게 운영 규모를 확대하기 쉽게 해줘요.', 'C1', 'technology', 3, 'scale startup growth operations technology', 14),
('col_technology_15', 'access', 'a network', 'access a network', '네트워크에 접속하다', 'connect', '"connect to a network"도 맞지만 access는 네트워크에 들어가는 것을 강조해요.', 'Remote workers can securely access the company network via VPN.', '원격 근무자는 VPN을 통해 회사 네트워크에 안전하게 접속할 수 있어요.', 'She couldn''t access the network because she forgot her password.', '그녀는 비밀번호를 잊어서 네트워크에 접속할 수 없었어요.', 'B1', 'technology', 1, 'network access internet connection technology', 15),
('col_technology_16', 'migrate', 'to the cloud', 'migrate to the cloud', '클라우드로 이전하다', 'move', '"move to the cloud"도 맞지만 migrate는 데이터나 시스템의 공식적인 이전을 강조해요.', 'The company plans to migrate all its data to the cloud by next year.', '회사는 내년까지 모든 데이터를 클라우드로 이전할 계획이에요.', 'Migrating to the cloud can reduce infrastructure costs significantly.', '클라우드로 이전하면 인프라 비용을 크게 줄일 수 있어요.', 'B2', 'technology', 2, 'cloud migration data storage server', 16),
('col_technology_17', 'detect', 'a bug', 'detect a bug', '버그를 발견하다', 'find', '"find a bug"도 맞지만 detect는 자동화된 시스템이나 테스트 도구를 통해 발견하는 뉘앙스예요.', 'The testing software detected a critical bug before the product launched.', '테스팅 소프트웨어는 제품 출시 전에 심각한 버그를 발견했어요.', 'It can be hard to detect bugs in complex software without proper tools.', '적절한 도구 없이 복잡한 소프트웨어에서 버그를 발견하기 어려울 수 있어요.', 'B2', 'technology', 2, 'bug detection software testing code', 17),
('col_technology_18', 'roll out', 'an update', 'roll out an update', '업데이트를 단계적으로 배포하다', 'give', '"give an update"도 맞지만 roll out은 단계적이고 계획적인 배포를 강조해요.', 'The company rolled out the update to users in phases.', '회사는 단계적으로 사용자에게 업데이트를 배포했어요.', 'They plan to roll out the new feature globally next month.', '그들은 다음 달에 전 세계적으로 새 기능을 배포할 계획이에요.', 'C1', 'technology', 3, 'rollout update deployment software release', 18),
('col_technology_19', 'disrupt', 'an industry', 'disrupt an industry', '산업을 혁신하다', 'change', '"change an industry"도 맞지만 disrupt는 기존 질서를 뒤흔드는 혁신적인 변화를 강조해요.', 'Smartphones disrupted the photography industry almost overnight.', '스마트폰은 거의 하룻밤 사이에 사진 산업을 혁신했어요.', 'AI has the potential to disrupt almost every industry in the world.', 'AI는 세계의 거의 모든 산업을 혁신할 잠재력을 가지고 있어요.', 'C1', 'technology', 3, 'disruption innovation industry tech AI', 19),
('col_technology_20', 'harness', 'technology', 'harness technology', '기술을 활용하다', 'use', '"use technology"도 맞지만 harness는 기술의 잠재력을 최대한 활용하는 뉘앙스예요.', 'The organization harnesses technology to deliver better services to its users.', '그 조직은 사용자에게 더 나은 서비스를 제공하기 위해 기술을 활용해요.', 'We need to harness technology responsibly to address global challenges.', '글로벌 과제를 해결하기 위해 기술을 책임감 있게 활용해야 해요.', 'C1', 'technology', 3, 'technology harness innovation solution digital', 20);
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('col_news_01', 'break', 'news', 'break news', '뉴스를 처음 보도하다', 'say', '"say news"는 틀린 표현이에요. 뉴스를 처음 전할 때는 break news 또는 report를 써요.', 'The journalist broke the news of the minister''s resignation.', '기자는 장관의 사임 소식을 처음 보도했어요.', 'It''s always difficult to break bad news to someone.', '누군가에게 나쁜 소식을 처음 전하는 것은 항상 어려워요.', 'B1', 'news', 1, 'news breaking report media journalism', 1),
('col_news_02', 'cover', 'a story', 'cover a story', '기사를 취재하다', 'write', '"write a story"도 맞지만 cover는 취재부터 보도까지의 전 과정을 강조해요.', 'The reporter covered the story from the front lines of the conflict.', '기자는 분쟁 최전선에서 기사를 취재했어요.', 'She has covered major international stories for over 20 years.', '그녀는 20년 이상 주요 국제 기사를 취재해 왔어요.', 'B1', 'news', 1, 'reporter journalist story news media', 2),
('col_news_03', 'publish', 'an article', 'publish an article', '기사를 게재하다', 'put', '"put an article"은 어색해요. 기사를 공식 게재할 때는 publish를 써요.', 'The newspaper published an article exposing corruption in the local government.', '신문은 지방 정부의 부패를 폭로하는 기사를 게재했어요.', 'She published her first article at the age of 22.', '그녀는 22세에 첫 기사를 게재했어요.', 'B1', 'news', 1, 'article publish newspaper media journalism', 3),
('col_news_04', 'report', 'on an event', 'report on an event', '사건을 보도하다', 'tell', '"tell about an event"도 맞지만 report on은 언론의 공식적인 보도를 강조해요.', 'Journalists reported on the protest from multiple viewpoints.', '기자들은 여러 관점에서 시위를 보도했어요.', 'The television crew was on the ground to report on the disaster.', '텔레비전 취재팀이 재해를 보도하기 위해 현장에 있었어요.', 'B1', 'news', 1, 'report event journalism media news', 4),
('col_news_05', 'investigate', 'a claim', 'investigate a claim', '주장을 조사하다', 'check', '"check a claim"도 맞지만 investigate는 더 철저하고 체계적인 조사를 강조해요.', 'The journalist spent months investigating the company''s claims.', '기자는 몇 달 동안 그 회사의 주장을 조사했어요.', 'Editors have a responsibility to investigate claims before publishing.', '편집자들은 게재하기 전에 주장을 조사할 책임이 있어요.', 'B2', 'news', 2, 'investigation journalism claim research fact', 5),
('col_news_06', 'run', 'a headline', 'run a headline', '헤드라인을 싣다', 'write', '"write a headline"도 맞지만 run은 신문이나 방송이 헤드라인을 내보내는 것을 강조해요.', 'The newspaper ran a sensational headline that caused a public outcry.', '신문은 대중의 분노를 야기한 선정적인 헤드라인을 실었어요.', 'All the major papers ran the same headline on their front pages.', '모든 주요 신문이 1면에 동일한 헤드라인을 실었어요.', 'B2', 'news', 2, 'headline newspaper front page media', 6),
('col_news_07', 'confirm', 'a report', 'confirm a report', '보도를 확인하다', 'check', '"check a report"도 맞지만 confirm은 내용의 사실 여부를 공식적으로 확인하는 뉘앙스예요.', 'The spokesperson confirmed the report of the prime minister''s resignation.', '대변인은 총리의 사임에 관한 보도를 확인했어요.', 'Neither the company nor the government would confirm the report.', '회사도 정부도 그 보도를 확인하려 하지 않았어요.', 'B1', 'news', 1, 'confirm report fact official news media', 7),
('col_news_08', 'retract', 'a story', 'retract a story', '기사를 철회하다', 'remove', '"remove a story"도 쓰이지만 retract는 잘못된 정보를 공식적으로 철회하는 뉘앙스예요.', 'The newspaper was forced to retract the story after new evidence emerged.', '신문은 새로운 증거가 나오자 기사를 철회할 수밖에 없었어요.', 'The editor issued an apology when they retracted the false report.', '편집장은 허위 보도를 철회하면서 사과문을 발표했어요.', 'C1', 'news', 3, 'retraction newspaper correction error media', 8),
('col_news_09', 'spread', 'misinformation', 'spread misinformation', '잘못된 정보를 퍼뜨리다', 'share', '"share misinformation"도 맞지만 spread는 정보가 광범위하게 퍼지는 뉘앙스예요.', 'Social media platforms are often used to spread misinformation.', '소셜 미디어 플랫폼은 종종 잘못된 정보를 퍼뜨리는 데 사용돼요.', 'It''s important to verify information before spreading it online.', '온라인에서 정보를 퍼뜨리기 전에 확인하는 것이 중요해요.', 'B2', 'news', 2, 'misinformation social media fake news spread', 9),
('col_news_10', 'fact-check', 'a source', 'fact-check a source', '출처를 팩트체크하다', 'verify', '"verify a source"도 맞지만 fact-check는 뉴스의 사실 여부를 검증하는 특화된 표현이에요.', 'Good journalists fact-check every source before including it in an article.', '좋은 기자들은 기사에 포함하기 전에 모든 출처를 팩트체크해요.', 'Several organisations were set up to fact-check claims made by politicians.', '정치인들의 주장을 팩트체크하기 위해 여러 단체가 설립됐어요.', 'B2', 'news', 2, 'fact check journalism verification truth media', 10),
('col_news_11', 'issue', 'a statement', 'issue a statement', '성명을 발표하다', 'say', '"say a statement"는 어색해요. 공식 성명을 낼 때는 issue 또는 release를 써요.', 'The company issued a statement denying the allegations.', '회사는 혐의를 부인하는 성명을 발표했어요.', 'The government issued a statement urging calm after the incident.', '정부는 사건 후 냉정을 촉구하는 성명을 발표했어요.', 'B2', 'news', 2, 'statement official press release government', 11),
('col_news_12', 'go', 'viral', 'go viral', '바이럴이 되다', 'become', '"become viral"도 쓰이지만 go viral이 훨씬 더 자연스러운 표현이에요.', 'The video of the incident went viral within hours of being posted.', '사건 영상은 게시된 지 몇 시간 만에 바이럴이 됐어요.', 'A single tweet went viral and changed the course of the story.', '하나의 트윗이 바이럴이 돼서 기사의 흐름을 바꿨어요.', 'B1', 'news', 1, 'viral social media internet news trend', 12),
('col_news_13', 'conduct', 'an interview', 'conduct an interview', '인터뷰를 하다', 'do', '"do an interview"도 맞지만 conduct는 더 격식 있고 전문적인 인터뷰를 강조해요.', 'The journalist conducted an interview with the prime minister.', '기자는 총리와 인터뷰를 했어요.', 'She has conducted thousands of interviews over her 30-year career.', '그녀는 30년 경력 동안 수천 건의 인터뷰를 했어요.', 'B1', 'news', 1, 'interview journalist media news conduct', 13),
('col_news_14', 'cite', 'a source', 'cite a source', '출처를 인용하다', 'name', '"name a source"도 맞지만 cite는 공식적으로 출처를 명시하는 뉘앙스예요.', 'The report cited anonymous sources within the government.', '그 보도는 정부 내 익명의 출처를 인용했어요.', 'Always cite your sources to maintain journalistic credibility.', '언론의 신뢰성을 유지하기 위해 항상 출처를 인용하세요.', 'B2', 'news', 2, 'source citation reference journalism media', 14),
('col_news_15', 'raise', 'a concern', 'raise a concern', '우려를 제기하다', 'say', '"say a concern"은 어색해요. 우려 사항을 공식적으로 언급할 때는 raise를 써요.', 'The report raised serious concerns about data privacy.', '그 보도는 데이터 프라이버시에 대한 심각한 우려를 제기했어요.', 'Several journalists raised concerns about editorial independence.', '여러 기자들이 편집 독립에 대한 우려를 제기했어요.', 'B2', 'news', 2, 'concern news report media issue', 15),
('col_news_16', 'lead', 'with a story', 'lead with a story', '기사를 첫 번째로 다루다', 'start', '"start with a story"도 맞지만 lead with는 편집 결정으로 첫 뉴스로 다루는 뉘앙스예요.', 'The evening news led with the story of the earthquake.', '저녁 뉴스는 지진 기사를 첫 번째로 다뤘어요.', 'Most news channels led with the same story about the election result.', '대부분의 뉴스 채널이 선거 결과에 관한 동일한 기사를 첫 번째로 다뤘어요.', 'C1', 'news', 3, 'headline lead news broadcast editorial', 16),
('col_news_17', 'uncover', 'a scandal', 'uncover a scandal', '스캔들을 폭로하다', 'find', '"find a scandal"도 맞지만 uncover는 숨겨진 것을 드러내는 뉘앙스예요.', 'The investigative team uncovered a major political scandal.', '탐사보도팀은 대규모 정치 스캔들을 폭로했어요.', 'The reporter uncovered the scandal after months of investigation.', '기자는 몇 달간의 조사 끝에 스캔들을 폭로했어요.', 'B2', 'news', 2, 'scandal uncover investigation journalism reveal', 17),
('col_news_18', 'balance', 'coverage', 'balance coverage', '균형 있게 보도하다', 'control', '"control coverage"는 어색해요. 공정한 보도를 위해서는 balance coverage를 써요.', 'A responsible journalist always balances coverage of both sides.', '책임감 있는 기자는 항상 양측을 균형 있게 보도해요.', 'Critics argued the channel failed to balance its coverage of the election.', '비평가들은 그 채널이 선거 보도를 균형 있게 하지 못했다고 주장했어요.', 'C1', 'news', 3, 'balance media coverage fair journalism', 18),
('col_news_19', 'quote', 'a source', 'quote a source', '출처를 인용하다', 'use', '"use a source"도 맞지만 quote는 출처의 말을 그대로 인용하는 것을 강조해요.', 'The article quoted a senior official who asked to remain anonymous.', '그 기사는 익명을 요청한 고위 관료를 인용했어요.', 'Journalists must ensure they quote sources accurately.', '기자들은 출처를 정확하게 인용해야 해요.', 'B1', 'news', 1, 'quote source journalism media reference', 19),
('col_news_20', 'hold', 'a press conference', 'hold a press conference', '기자회견을 열다', 'make', '"make a press conference"는 어색해요. 기자회견을 개최할 때는 hold를 써요.', 'The prime minister held a press conference to address the allegations.', '총리는 혐의에 대해 해명하기 위해 기자회견을 열었어요.', 'The company held a press conference to announce the merger.', '회사는 합병을 발표하기 위해 기자회견을 열었어요.', 'B1', 'news', 1, 'press conference media journalism official announcement', 20);
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('col_academic_01', 'submit', 'an essay', 'submit an essay', '에세이를 제출하다', 'give', '"give an essay"는 어색해요. 과제를 제출할 때는 submit 또는 hand in을 써요.', 'Students must submit their essays by midnight on Friday.', '학생들은 금요일 자정까지 에세이를 제출해야 해요.', 'She submitted her essay a day early to avoid last-minute stress.', '그녀는 마지막 순간의 스트레스를 피하기 위해 하루 일찍 에세이를 제출했어요.', 'B1', 'academic', 1, 'essay submit university assignment deadline', 1),
('col_academic_02', 'attend', 'a lecture', 'attend a lecture', '강의에 참석하다', 'go', '"go to a lecture"도 맞지만 attend는 더 격식 있는 표현이에요.', 'She attended every lecture despite having a part-time job.', '그녀는 아르바이트를 하면서도 모든 강의에 참석했어요.', 'Students who attend lectures regularly tend to perform better in exams.', '강의에 규칙적으로 참석하는 학생들은 시험에서 더 좋은 성과를 내는 경향이 있어요.', 'B1', 'academic', 1, 'lecture university class attend study', 2),
('col_academic_03', 'take', 'notes', 'take notes', '필기하다', 'write', '"write notes"도 맞지만 take notes는 수업 중에 필기하는 것을 강조해요.', 'He always takes detailed notes during lectures.', '그는 항상 강의 중에 자세한 필기를 해요.', 'Taking good notes helps you review the material more effectively.', '좋은 필기를 하면 내용을 더 효과적으로 복습할 수 있어요.', 'A2', 'academic', 1, 'notes study lecture writing class', 3),
('col_academic_04', 'pass', 'an exam', 'pass an exam', '시험에 합격하다', 'succeed', '"succeed in an exam"도 맞지만 pass an exam이 훨씬 더 자연스러운 표현이에요.', 'She worked very hard and passed all her exams with distinction.', '그녀는 매우 열심히 공부해서 모든 시험에 우수한 성적으로 합격했어요.', 'You need to pass the exam to qualify for the next level.', '다음 단계로 진급하려면 시험에 합격해야 해요.', 'B1', 'academic', 1, 'exam pass study success university', 4),
('col_academic_05', 'enrol in', 'a course', 'enrol in a course', '과정에 등록하다', 'join', '"join a course"도 쓰이지만 enrol in은 공식적인 등록 절차를 강조해요.', 'She enrolled in an online course to improve her academic writing.', '그녀는 학문적 글쓰기를 향상시키기 위해 온라인 과정에 등록했어요.', 'How many students enrolled in the linguistics course this year?', '올해 언어학 과정에 몇 명의 학생이 등록했어요?', 'B1', 'academic', 1, 'enrolment course university study registration', 5),
('col_academic_06', 'write', 'a thesis', 'write a thesis', '논문을 쓰다', 'make', '"make a thesis"는 어색해요. 학위 논문을 작성할 때는 write a thesis를 써요.', 'He spent two years writing his doctoral thesis.', '그는 박사 학위 논문을 쓰는 데 2년을 보냈어요.', 'Writing a thesis requires strong research and critical thinking skills.', '논문을 쓰는 것은 강한 연구 및 비판적 사고 능력을 요구해요.', 'B2', 'academic', 2, 'thesis research writing university graduate', 6),
('col_academic_07', 'earn', 'a degree', 'earn a degree', '학위를 취득하다', 'get', '"get a degree"도 맞지만 earn은 노력을 통해 성취한다는 뉘앙스예요.', 'She earned a degree in computer science from Seoul National University.', '그녀는 서울대학교에서 컴퓨터공학 학위를 취득했어요.', 'He earned his degree while working full-time at a technology company.', '그는 기술 회사에서 전일제로 일하면서 학위를 취득했어요.', 'B1', 'academic', 1, 'degree university graduation achievement education', 7),
('col_academic_08', 'review', 'the literature', 'review the literature', '문헌을 검토하다', 'read', '"read the literature"도 맞지만 review는 비판적으로 검토하고 종합하는 뉘앙스예요.', 'The first step in any research project is to review the existing literature.', '모든 연구 프로젝트의 첫 번째 단계는 기존 문헌을 검토하는 것이에요.', 'She reviewed the literature to identify gaps in current research.', '그녀는 현재 연구의 공백을 파악하기 위해 문헌을 검토했어요.', 'B2', 'academic', 2, 'literature review research academic study', 8),
('col_academic_09', 'formulate', 'a hypothesis', 'formulate a hypothesis', '가설을 세우다', 'make', '"make a hypothesis"도 쓰이지만 formulate는 더 체계적이고 논리적인 과정을 강조해요.', 'The scientist formulated a hypothesis based on her preliminary observations.', '과학자는 예비 관찰을 바탕으로 가설을 세웠어요.', 'Students must formulate a clear hypothesis before beginning their experiments.', '학생들은 실험을 시작하기 전에 명확한 가설을 세워야 해요.', 'B2', 'academic', 2, 'hypothesis science research experiment study', 9),
('col_academic_10', 'apply', 'for a scholarship', 'apply for a scholarship', '장학금을 신청하다', 'get', '"get a scholarship"도 맞지만 apply for는 신청 과정을 강조해요. 먼저 신청해야 받을 수 있어요.', 'She applied for a scholarship to fund her postgraduate studies.', '그녀는 대학원 학업 자금을 마련하기 위해 장학금을 신청했어요.', 'You should apply for as many scholarships as you are eligible for.', '자격이 되는 장학금에 최대한 많이 신청해야 해요.', 'B1', 'academic', 1, 'scholarship university funding apply education', 10),
('col_academic_11', 'sit', 'an exam', 'sit an exam', '시험을 치르다', 'take', '"take an exam"도 맞고 자주 쓰여요. sit an exam은 영국 영어에서 더 격식 있게 쓰여요.', 'Students must sit the final exam in the examination hall.', '학생들은 시험장에서 최종 시험을 치러야 해요.', 'She sat the entrance exam three times before passing.', '그녀는 합격하기까지 입학시험을 세 번 치렀어요.', 'B2', 'academic', 2, 'exam university test hall formal', 11),
('col_academic_12', 'plagiarise', 'work', 'plagiarise work', '작업물을 표절하다', 'copy', '"copy work"도 맞지만 plagiarise는 다른 사람의 작업을 자신의 것처럼 제출하는 구체적인 행위예요.', 'Students who plagiarise work face serious academic consequences.', '작업물을 표절한 학생들은 심각한 학문적 결과에 직면해요.', 'Always cite your sources — plagiarising even a paragraph is unacceptable.', '항상 출처를 인용하세요. 단 하나의 단락을 표절하는 것도 용납되지 않아요.', 'C1', 'academic', 3, 'plagiarism academic integrity essay university', 12),
('col_academic_13', 'defend', 'a thesis', 'defend a thesis', '논문을 구두 심사에서 발표하다', 'present', '"present a thesis"도 맞지만 defend는 심사위원의 질문에 답하는 구두 시험을 강조해요.', 'She successfully defended her thesis in front of a panel of professors.', '그녀는 교수 심사 패널 앞에서 논문을 성공적으로 발표했어요.', 'Defending your thesis is one of the most challenging parts of a PhD.', '논문 구두 심사는 박사 과정에서 가장 도전적인 부분 중 하나예요.', 'C1', 'academic', 3, 'thesis defense PhD university examination', 13),
('col_academic_14', 'meet', 'a deadline', 'meet a deadline', '마감 기한을 맞추다', 'do', '"do a deadline"은 틀린 표현이에요. 마감 기한을 지킬 때는 meet a deadline을 써요.', 'She struggled to meet the deadline for her research paper.', '그녀는 연구 논문의 마감 기한을 맞추기 위해 애썼어요.', 'Good time management is essential if you want to meet every deadline.', '모든 마감 기한을 맞추고 싶다면 좋은 시간 관리가 필수예요.', 'B1', 'academic', 1, 'deadline time management university assignment', 14),
('col_academic_15', 'score', 'high marks', 'score high marks', '높은 점수를 받다', 'get', '"get high marks"도 맞지만 score는 시험이나 과제에서 특정 점수를 얻는 것을 강조해요.', 'She scored the highest marks in the class on the final exam.', '그녀는 기말고사에서 반에서 가장 높은 점수를 받았어요.', 'Hard work and preparation are the keys to scoring high marks.', '열심히 공부하고 준비하는 것이 높은 점수를 받는 열쇠예요.', 'B1', 'academic', 1, 'marks score exam grade university', 15),
('col_academic_16', 'take', 'a gap year', 'take a gap year', '갭이어를 갖다', 'do', '"do a gap year"도 쓰이지만 take a gap year가 훨씬 더 자연스러운 표현이에요.', 'She decided to take a gap year before starting her university studies.', '그녀는 대학 공부를 시작하기 전에 갭이어를 갖기로 결심했어요.', 'Many students take a gap year to travel and gain real-world experience.', '많은 학생들이 여행하고 실제 경험을 쌓기 위해 갭이어를 가져요.', 'B1', 'academic', 1, 'gap year travel university experience education', 16),
('col_academic_17', 'pursue', 'a degree', 'pursue a degree', '학위 취득을 추구하다', 'study for', '"study for a degree"도 맞지만 pursue는 더 목표 지향적인 뉘앙스예요.', 'She decided to pursue a degree in international relations.', '그녀는 국제 관계학 학위 취득을 추구하기로 결심했어요.', 'He pursued a degree online while working full-time.', '그는 전일제로 일하면서 온라인으로 학위 취득을 추구했어요.', 'B2', 'academic', 2, 'degree university pursue education goal', 17),
